def find_peak(arr):
    n = len(arr)
    if n == 0:
        return -1
    if n == 1:
        return 0

    low = 0
    high = n - 1

    while low <= high:
        mid = low + (high - low) // 2

        is_left_smaller = (mid == 0 or arr[mid] > arr[mid - 1])
        is_right_smaller = (mid == n - 1 or arr[mid] > arr[mid + 1])

        if is_left_smaller and is_right_smaller:
            return mid
        elif is_left_smaller:
            # Current element is greater than its left neighbor but smaller than its right neighbor.
            # This means we are on the increasing slope, so the peak must be to the right.
            low = mid + 1
        else:
            # Current element is smaller than its left neighbor.
            # This means we are on the decreasing slope, so the peak must be to the left.
            high = mid - 1
    return -1


def binary_search_increasing(arr, target, low, high):
    while low <= high:
        mid = low + (high - low) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            low = mid + 1
        else:
            high = mid - 1
    return -1


def binary_search_decreasing(arr, target, low, high):
    while low <= high:
        mid = low + (high - low) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] > target:
            # Target is smaller than arr[mid], so in a decreasing array,
            # it must be to the right (at a larger index).
            low = mid + 1
        else:
            # Target is larger than arr[mid], so in a decreasing array,
            # it must be to the left (at a smaller index).
            high = mid - 1
    return -1


def search_bitonic(arr, target):
    n = len(arr)
    if n == 0:
        return -1

    peak_idx = find_peak(arr)
    if peak_idx == -1:
        # This case should ideally not be reached for a valid bitonic array of length >= 1.
        return -1

    # Search in the increasing part of the array (from index 0 to peak_idx)
    result = binary_search_increasing(arr, target, 0, peak_idx)
    if result != -1:
        return result

    # If not found in the increasing part, search in the decreasing part
    # (from peak_idx + 1 to the end of the array)
    result = binary_search_decreasing(arr, target, peak_idx + 1, n - 1)
    return result
